from __future__ import annotations

import json
from datetime import datetime, timezone
from typing import Any


EVENT_LABELS = {
    "exercise": "活动", "meal": "饮食", "sleep": "睡眠", "body": "身体",
    "mood": "感受", "symptom": "症状", "menstrual_cycle": "周期",
    "blood_pressure": "血压", "blood_glucose": "血糖", "medical_report": "医疗报告",
}


def render_dashboard_html(snapshot: dict[str, Any]) -> str:
    payload = json.dumps(snapshot, ensure_ascii=False, separators=(",", ":")).replace("</", "<\\/")
    name = snapshot["profile"].get("display_name") or "我的健康"
    goal = snapshot["profile"].get("primary_goal") or "持续了解身体状态"
    return (
        _TEMPLATE.replace("__PAYLOAD__", payload)
        .replace("__NAME__", _escape(name))
        .replace("__GOAL__", _escape(goal))
        .replace("__TIMEZONE__", _escape(snapshot["profile"].get("timezone") or "Asia/Shanghai"))
        .replace("__GENERATED__", _escape(snapshot["generated_at"][:19]))
    )


def dashboard_snapshot(
    *,
    daily: dict[str, Any],
    weekly: dict[str, Any],
    monthly: dict[str, Any],
    events: list[dict[str, Any]],
    archive: list[dict[str, str]],
    profile: dict[str, Any],
    trends: dict[str, Any],
) -> dict[str, Any]:
    return {
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "profile": {
            "display_name": profile.get("display_name") or "",
            "primary_goal": profile.get("primary_goal") or "",
            "timezone": profile.get("timezone") or "Asia/Shanghai",
            "details": profile.get("details") or {},
        },
        "models": {"daily": daily, "weekly": weekly, "monthly": monthly},
        "trends": trends,
        "events": events,
        "archive": archive,
    }


def _escape(value: str) -> str:
    return value.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace('"', "&quot;")


